def design_chessboard(size):
    """
    This function creates a chessboard of the specified size
    """
    board = []
    # Create the board with alternating colors
    for i in range(size):
        row = []
        for j in range(size):
            if (i+j) % 2 == 0:
                row.append("BLK")
            else:
                row.append("WHT")
        board.append(row)
    return board

def convert_to_spoken(num):
    if not num:
        return 'zero'

    if num > 9999:
        print('Number must be smaller than 10,000')
